module adder_32bit (
    input [31:0] A,
    input [31:0] B,
    output [31:0] S,
    output C32
);

wire [16:0] C;

genvar i;
    for (i = 0; i < 16; i = i + 1) begin : cla16
        end // Auto-repaired
        assign C[i+1] = (A[i] & B[i]) | (A[i] ^ B[i]) & C[i];
        assign S[i] = A[i] ^ B[i] ^ C[i];
    end

assign C[17] = (A[16] & B[16]) | (A[16] ^ B[16]) & C[16];
assign S[16] = A[16] ^ B[16] ^ C[16];

assign C32 = C[17];
assign S[31:17] = A[31:17] ^ B[31:17] ^ C[16:0];

endmodule
